def expected_tokens_per_call(alpha: float, K: int) -> float:
    """Expected accepted tokens (including bonus) per target forward pass."""
    if alpha >= 1.0 - 1e-9:
        return K + 1
    return (1 - alpha ** (K + 1)) / (1 - alpha)

def effective_speedup(alpha: float, K: int, gamma: float) -> float:
    """
    Wall-clock speedup over autoregressive baseline.
    gamma = T_draft_step / T_target_step (typically 0.05–0.20 for a 10-20x smaller draft model)
    """
    return expected_tokens_per_call(alpha, K) / (1 + K * gamma)

def break_even_alpha(K: int, gamma: float) -> float:
    """Minimum alpha for speedup > 1.0 (where spec decoding beats baseline)."""
    for a10k in range(0, 10001):
        a = a10k / 10000.0
        if effective_speedup(a, K, gamma) > 1.0:
            return a
    return 1.0

# Example analysis
gamma = 0.10   # draft is 10% of target cost (e.g. 7B draft vs 70B target)
for K in [2, 4, 6, 8]:
    for alpha in [0.6, 0.75, 0.85, 0.90, 0.95]:
        sp = effective_speedup(alpha, K, gamma)
        print(f"K={K}  alpha={alpha:.2f}  speedup={sp:.2f}x")
    be = break_even_alpha(K, gamma)
    print(f"  break-even alpha for K={K}, gamma={gamma}: {be:.3f}")
    print()
